<section class="panel form-panel wide-form"><div class="panel-header"><div><span class="section-kicker">Logistique commerciale</span><h2>Préparer la livraison · <?= e($order['reference']); ?></h2><p class="ui-page-intro">Indiquez les quantités réellement expédiées pour chaque article de la commande.</p></div><a class="btn btn-secondary" href="<?= url('sales_orders/show?id='.(int)$order['id']); ?>"><i class="bi bi-arrow-left"></i> Retour à la commande</a></div><?php if($m=Session::flash('error')): ?><div class="alert alert-danger"><?= e($m); ?></div><?php endif; ?><form method="post" action="<?= url('deliveries/store'); ?>" data-validate><?= Csrf::field(); ?><input type="hidden" name="sales_order_id" value="<?= (int)$order['id']; ?>"><div class="table-responsive"><table class="data-table"><thead><tr><th>Article</th><th class="text-right">Quantité commandée</th><th class="text-right">Déjà livrée</th><th class="text-right">À livrer maintenant</th></tr></thead><tbody><?php foreach($items as $i): $remaining=(float)$i['quantity']-(float)$i['delivered_quantity']; ?><tr><td><?= e($i['description']); ?></td><td class="text-right"><?= e($i['quantity']); ?></td><td class="text-right"><?= e($i['delivered_quantity']); ?></td><td class="text-right"><input type="number" step="0.01" min="0" max="<?= e((string)$remaining); ?>" name="quantities[<?= (int)$i['id']; ?>]" value="<?= e((string)$remaining); ?>"></td></tr><?php endforeach; ?></tbody></table></div><label class="span-2">Notes de livraison <textarea name="notes" rows="3" placeholder="Réserves, instructions ou informations de remise…"></textarea></label><div class="form-actions"><a class="btn btn-secondary" href="<?= url('sales_orders/show?id='.(int)$order['id']); ?>">Annuler</a><button class="btn btn-primary" type="submit"><i class="bi bi-truck"></i> Enregistrer la livraison</button></div></form></section>
